    97	func applyCustomInflections(name string, inflections []Inflection) (string, bool) {
    98		lower := strings.ToLower(name)
    99		for _, inflection := range inflections {
   100			if inflection.Singular == "" || inflection.Plural == "" {
   101				continue
   102			}
   103	
   104			pluralLower := strings.ToLower(inflection.Plural)
   105			if !strings.HasSuffix(lower, pluralLower) {
   106				continue
   107			}
   108	
   109			offset := len(name) - len(inflection.Plural)
   110			return name[:offset] + matchIdentifierCase(name[offset:], inflection.Singular), true
   111		}
   112	
   113		return "", false
   114	}
