   156	func identifierWords(s string) []string {
   157		if s == "" {
   158			return nil
   159		}
   160	
   161		words := make([]string, 0, 4)
   162		start := 0
   163		for i := 1; i < len(s); i++ {
   164			prev := s[i-1]
   165			curr := s[i]
   166			var next byte
   167			if i+1 < len(s) {
   168				next = s[i+1]
   169			}
   170	
   171			if isUpperASCII(curr) && (isLowerASCII(prev) || isDigitASCII(prev)) {
   172				words = append(words, s[start:i])
   173				start = i
   174				continue
   175			}
   176			if isUpperASCII(prev) && isUpperASCII(curr) && next != 0 && isLowerASCII(next) {
   177				if next == 's' && (i+2 == len(s) || isUpperASCII(s[i+2])) {
   178					continue
   179				}
   180				words = append(words, s[start:i])
   181				start = i
   182			}
   183		}
   184	
   185		words = append(words, s[start:])
   186		return words
   187	}
